var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 뭐야, 이것들은?","JPN":"うん？　なにこれ？","ENG":"Huh? What's going on here?","TWN":"咦？你們在幹嘛？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"모의전투실이 왜 이렇게 바글바글해?","JPN":"模擬戦闘室が何でこんなに混んでるの？","ENG":"Why's the Sim Center so crowded?","TWN":"都聚在模擬戰鬥室幹什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘......?","JPN":"ナイエル……？","ENG":"Naielle?","TWN":"奈爾……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흐흥. 누군가 했더니 학생회의 관심종자에 낙오자 선배잖아.","JPN":"ふーん、誰かと思ったら、生徒会に迷惑かけっぱなしの落ちこぼれ先輩じゃない。","ENG":"Hmpf. Well, it's the Student Council's attention-hungry clown and the loser senior.","TWN":"哼。我還以為是誰呢，原來是學生會的自戀狂和留級生前輩啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"내가 분명 여기서 얼쩡거리지 말라고 했을 텐데?","JPN":"この前ここでウロチョロしないでって言ったはずよ？","ENG":"Didn't I tell you to stay away from this place?","TWN":"我明明跟你們說過，不要到這裡來！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"미, 미안해. 알렌 선생님이 보충수업을 하라고 하셔서......","JPN":"ご、ごめんね。アレン先生から補習が必要って言われて……","ENG":"S-sorry. Mr. Birmingham told me to finish my makeup session...","TWN":"對、對不起。艾倫老師讓我來這邊補課……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그딴 건 내가 알 바 아니야!","JPN":"そんなの知ったこっちゃないわ！","ENG":"I couldn't care less!","TWN":"那個與我無關！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"애초에 졸업도 못할 낙오자가 보충수업 같은 걸 받아서 어쩌겠다는 건데?","JPN":"卒業すらできそうにない劣等生が補習を受けたところで何も変わんないでしょ？","ENG":"What good will makeup sessions do if you're never going to graduate?","TWN":"像你這樣註定不能畢業的人，補課又有什麼意義呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭣보다 선배가 근처에 있으면 낙오자 냄새가 진동해서 훈련에 방해된단 말이야.","JPN":"ていうか、先輩が近くにいると負け犬の臭いが充満して訓練に集中できないのよ。","ENG":"Besides, your loser stench is too distracting when I'm trying to train.","TWN":"重要的是只要有前輩在就讓人倒盡胃口，會妨礙我訓練的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"자기가 얼마나 민폐 덩어리인지 알고나 있는 거야?","JPN":"自分がどれだけ周りに迷惑かけてるか、わかってないでしょ？","ENG":"Do you have any idea what a sore sight you are?","TWN":"你自己都不知道自己有多礙眼嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"내, 내가 잘못했어...... 지금 나갈게......","JPN":"ご、ごめん……今すぐ出るから……","ENG":"M-my bad... I'll leave now...","TWN":"我、我錯了…… 我現在就出去……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐!","JPN":"ちょっと！","ENG":"Hey!","TWN":"喂！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누군지 몰라도 말이 너무 심한 거 아냐?","JPN":"誰だか知らないけど、言い過ぎじゃない？","ENG":"Aren't you being a bit harsh, whoever you are?","TWN":"雖然不知道你是誰，但你太過分了吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"날 모른다고?","JPN":"私を知らないですって？","ENG":"You don't know who I am?","TWN":"你不認識我？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그러고 보니 처음 보는 얼굴이네.","JPN":"そういえば初めてみる顔ね。","ENG":"Oh, I guess I've never seen you around here either.","TWN":"看來你是新面孔啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미, 미나는 오늘 처음 등교한 편입생이야.","JPN":"ミ、ミナちゃんは今日初めて登校した編入生なの。","ENG":"M-Mina just transferred here today.","TWN":"米、米娜是今天第一天來學校的插班生。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흐음, 편입생이라......","JPN":"ふーん、編入生か……","ENG":"Hmm, a transfer student you say...","TWN":"哼，插班生……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"첫날부터 이딴 녀석들이랑 노닥거리는 걸 보니 너도 인생 패배자 후보생쯤 되나 보네.","JPN":"初日からこんな連中と戯れているってことは、あんたも負け組の仲間入りね。","ENG":"You must be a loser too, seeing as how you're hanging out with these dorks on your first day here.","TWN":"第一天就跟這樣的傢伙們為伍，看來你也註定是人生失敗者。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어쨌든 처음이라고 하니 가르쳐 주지.","JPN":"今日が初登校らしいし、一つ教えてやるわ。","ENG":"Well, let me teach you something since you're new.","TWN":"不管怎樣，畢竟是第一次，讓我來教教你吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이 모의전투실은 말이지, 나 같은 엘리트들을 위해 관리국에서 특별히 설치한 거야.","JPN":"この模擬戦闘室はね、私みたいなエリートのために管理局が特別に設置してくれたものなの。","ENG":"The Administration prepared this Combat Simulation Center for elite students like me.","TWN":"這個模擬戰鬥室，是管理局為了像我這樣的精英們而特別準備的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"니들 같은 낙오자들이 함부로 써도 되는 시설이 아니라고.","JPN":"あんたたちみたいな劣等生が勝手に使っていい施設じゃないのよ。","ENG":"It's not a playground for some losers like you.","TWN":"不是像你們這樣的人可以隨便用的設備。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 다시는 얼쩡거리지 마. 알겠어?","JPN":"だから二度とこの辺をウロチョロしないで。わかった？","ENG":"So don't you dare come anywhere near here again? Got that?","TWN":"所以，別讓我在這裡看到你們。聽懂了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으, 응......","JPN":"う、うん……","ENG":"O-okay...","TWN":"嗯，嗯……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"쳇, 대체 시뮬레이터를 몇 번이나 돌린 거야?","JPN":"ちょっと、シミュレーターを何回使ったの？","ENG":"Hmpf, how many times did you go on this simulator anyway?","TWN":"切，也不知道你啟動了幾次戰鬥模擬器？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이러다 나한테도 낙오자 냄새가 묻으면 어쩔 건데?","JPN":"私に負け犬の臭いが移ったらどうするの！","ENG":"You'd better not get your loser smell on me!","TWN":"要是我接下來身上也沾到霉運，該怎麼辦？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 뭐 저딴 녀석이 다 있어!","JPN":"はあ？　なにあいつ！","ENG":"What the heck is wrong with that crazy jerk?","TWN":"怎麼會有這種人！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"차, 참아! 미나야!","JPN":"ま、待って！　ミナちゃん！","ENG":"C-calm down! Mina!","TWN":"忍忍吧！米娜！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"성격이 저래도 나이엘은 아카데미 최강의 엘리트 카운터란 말이야.","JPN":"性格はちょっとアレだけど、ナイエルはアカデミー最強のエリートカウンターなの。","ENG":"Naielle may be a jerk, but she's the best elite Counter in the entire Academy.","TWN":"性格雖然很跋扈，但奈爾是學院最強的精英制裁者。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학교 최강?","JPN":"アカデミー最強？","ENG":"The strongest?","TWN":"學校最強？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응, 실전 훈련에서 무려 2종 침식체를 혼자 쓰러뜨린 적도 있어.","JPN":"そう、実戦訓練でなんと第2種侵食体を一人で倒したこともあるの。","ENG":"Yeah, she even took down a Category 2 by herself in real combat training.","TWN":"嗯，在實戰訓練時，她曾獨自打敗2類侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"가끔 너처럼 용병으로 활동하다가 편입한 애들도 나이엘이랑 시비가 붙으면 크게 다쳐서 병원으로 실려 갔고.","JPN":"あなたのように傭兵出身で編入してきて、ナイエルと喧嘩になって大怪我をして病院に運ばれた子もいるよ。","ENG":"Lots of transfer students who used to be mercenaries like you got hospitalized after getting into arguments with Naielle.","TWN":"以前也有過像你這樣當過傭兵的學生與奈爾發生摩擦，最後都受重傷被送到了醫院。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나도 마음에 들진 않지만......","JPN":"私だって気に食わないけど……","ENG":"I don't like this any better than you do...","TWN":"雖然我也不喜歡她……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생들 중엔 학생회장님 말고는 이길 사람이 없을 거야.","JPN":"生徒の中で、生徒会長を除いたらあの子に勝てる人はいないと思う。","ENG":"But I don't think any student could beat her, except the Student President.","TWN":"但在學生當中，除了學生會長應該沒有人能贏她。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥. 그것도 이번에 예정된 다이브 실전 훈련이 끝나고 나면 바뀔걸.","JPN":"ふん。今回実施されるダイブ実戦訓練が終わったらそれも変わるわ。","ENG":"Hmpf! And even that's bound to change after the upcoming Dive training.","TWN":"哼，你說的這些在我完成躍入實戰訓練後，也會成為最新紀錄。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"난 이번에 3종 침식체를 사냥할 예정이거든.","JPN":"私は第3種侵食体を狩る予定なんだから。","ENG":"I plan on hunting a Category 3 this time.","TWN":"我這次準備狩獵3類侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"3종 침식체......?","JPN":"第3種侵食体……？","ENG":"Category 3?","TWN":"3類侵蝕體……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그건 아무리 너라도 위험해! 애초에 선생님들이 허락해 줄 리 없잖아!","JPN":"いくらあなたでもそれは危険だよ！　そもそも先生たちが許可するはずがない。","ENG":"That's way too dangerous, even for you! The faculty would never allow that!","TWN":"就算你厲害但那也太危險了！老師們不會同意的！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"물론 3종 침식체랑 혼자 싸우겠다는 멍청한 생각은 안 하지.","JPN":"もちろん第3種侵食体と一人で戦うなんてバカな真似はしない。","ENG":"Of course, I'm not stupid enough to take on a Category 3 by myself.","TWN":"我當然不會蠢到一個人去跟3類侵蝕體戰鬥了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 내가 직접 훈련시킨 사냥 팀 <color=#ffd34c>아이언 스틸</color>이라면 충분히 가능해!","JPN":"でも私が自ら訓練した狩りチーム<color=#ffd34c>アイアンスチール</color>となら十分できる！","ENG":"But the hunting team <color=#ffd34c>Iron Steel</color> that I trained myself will get the job done!","TWN":"但跟我親自訓練的狩獵隊<color=#ffd34c>鋼鐵</color>一起的話，就不會有什麼問題！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"귀찮은 선생들의 눈을 피할 방법도 충분히 마련해 뒀고 말이야.","JPN":"面倒くさい先生たちの目を避ける方法も用意しているしね。","ENG":"I've already figured out how to keep their eyes off me.","TWN":"至於老師那邊我已經想好對策了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니 기대하고 있는 게 좋을 거야.","JPN":"だから期待していいわ。","ENG":"So stay tuned.","TWN":"所以你可以盡請期待。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"제 3종 침식체 사냥이라는 위업을 달성하면, 란체스터 선배 다음 학생회장 자리는 보나마나 내 차지일 테니까.","JPN":"第3種侵食体狩りという偉業を達成すれば、ランチェスター先輩卒業後の生徒会長の座はこの私のものよ。","ENG":"Once I take down a Category 3, I'm going to be the next Student President for sure.","TWN":"當我完成狩獵3類侵蝕體的偉業時，蘭賈斯特前輩之後的下一任學生會長就非我莫屬了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그 때가 되면 너희 같은 낙오자들은 무슨 수를 써서든 퇴학시켜 버리겠어.","JPN":"そうなったら、あんたたちのような負け犬はどんな手を使ってでも退学させてやる。","ENG":"And when that day comes, I'll make sure losers like you get expelled.","TWN":"到時候，我一定會讓你們這樣的失敗者全都退學。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"마술사가 되어서 사람들에게 즐거움을 준다고? 침식체랑 싸우기가 무서워?","JPN":"マジシャンになって人々を笑顔にするって？　侵食体と戦うのが怖い？","ENG":"You want to become a magician? And you're too scared to fight C.O.s?","TWN":"想成為魔術師帶給人們歡樂？害怕與侵蝕體戰鬥？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"웃기고 있네. 너희가 가진 카운터 워치는 장식이야?","JPN":"笑わせないで。あんたたちの持つカウンターウォッチはただの飾りなの？","ENG":"What a joke. You think your Counter Watches are toys?","TWN":"真是搞笑。你們的制裁者能量環都是裝飾嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"관리국 카운터 아카데미는 오직 인류를 구할 영웅들을 육성하는 곳이야.","JPN":"管理局カウンターアカデミーは人類を助ける英雄を育成する場所。","ENG":"The Academy is a place to train heroes who will save humanity.","TWN":"管理局的制裁者學院是培養拯救人類英雄的地方。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 곳에 너희 같이 지원금만 축내는 것들이 설 자리는 없어.","JPN":"ここにあんたたちみたいな補助金を無駄にするだけの厄介者の居場所はないわ。","ENG":"There's no room for losers like you, bleeding the budget dry for no reason.","TWN":"這裡可不是你們這種浪費資源的傢伙們該待的地方。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저기...... 말 끊어서 미안한데......","JPN":"あのさ……話の途中で悪いけど……","ENG":"Hey... Sorry for interrupting...","TWN":"抱歉……打斷一下……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 녀석이 2종 침식체를 단독으로 사냥했다고?","JPN":"あいつが第2種侵食体を一人で倒したって？","ENG":"But that kid really took out a Category 2 by herself?","TWN":"那個傢伙獨自消滅了2類侵蝕體？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 미나 너도 믿기 힘들겠지만......","JPN":"うん、ミナちゃんにも信じがたい話だよね……","ENG":"Yeah. I know it's hard to believe, but...","TWN":"嗯。米娜雖然你也很難相信……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 그렇게 대단한 거야?","JPN":"それってそんなにすごいことなの？","ENG":"And that's supposed to be so impressive?","TWN":"那個有那麼了不起嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하......!","JPN":"は……？","ENG":"Hah!","TWN":"啊……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"무슨 소릴 하는 거야? 당연히 대단하지!","JPN":"何言ってるの？　そりゃあすごいよ！","ENG":"What are you talking about? Of course it's impressive!","TWN":"你在說什麼？當然很了不起啦！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭔 소릴 하나 했더니...... 우습지도 않네.","JPN":"何を言ってくるかと思ったら……笑えないわ。","ENG":"Oh, I see what you're trying to do here. Think you're funny, don't you?","TWN":"我還以為要說什麼呢……一點都不好笑。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"날 도발하려면 좀 더 머리를 쓰는 게 어때?","JPN":"私を挑発するならもっと頭を使えば？","ENG":"You'd better come up with more than that to provoke me into a fight.","TWN":"如果你想激怒我的話，我勸你多動動腦？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"2종 침식체의 관리국 표준 대응 지침은 <color=#ffd34c>B급 카운터 혹은 소대급 기갑 화력 동원</color>이라고.","JPN":"第2種侵食体の管理局標準対応指針は<color=#ffd34c>B級カウンターもしくは小隊級の機甲火力動員</color>なの。","ENG":"The Administration recommends <color=#ffd34c>Grade B Counters or fire support from an armor squad</color> when dealing with Category 2 C.O.s.","TWN":"對付2類侵蝕體的管理局標準是<color=#ffd34c>B級制裁者或者使用小隊級別的機甲火力</color>。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"최소한 주력 전차 3대 이상을 동원해야 상대가 되는 괴물이란 뜻이지.","JPN":"少なくとも主力戦車が3台以上はないと相手できない化物ってこと。","ENG":"Which means you'll need at least three main battle tanks to deal with those things.","TWN":"是至少需要3台以上的主力戰車才能對付的怪物。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하물며 3종 침식체는 말할 것도 없고.","JPN":"第3種侵食体なら言うまでもない。","ENG":"Needless to say, a Category 3 is even more formidable.","TWN":"那3類侵蝕體就更不用說了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너 같은 건 아마 구경해 본 적도 없을걸?","JPN":"あんたは見たことすらないでしょ？","ENG":"I bet you have never seen even one.","TWN":"你這樣的人，可能一輩子都見不到？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"3종 침식체라면 어제도 몇 마리 해치웠는데......?","JPN":"第3種侵食体なら昨日も何匹か倒したけど……？","ENG":"Uh, actually... I took out a few Category 3's just yesterday...","TWN":"3類侵蝕體的話，昨天也消滅了幾隻……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐......?","JPN":"なんですって……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"처음 만났을 땐 꽤 고전하긴 했어. 덩치가 엄청 컸거든.","JPN":"初めて出くわした時はかなり苦労したけどね。結構大きくて。","ENG":"Granted, I had a pretty tough time fighting them at first. I mean, those things are huge.","TWN":"一開始交手的時候確實吃力。因為塊頭實在是太大了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 지금이라면 그럭저럭 상대할 만해.","JPN":"でも今ならまあまあ相手できるくらいかな。","ENG":"But nowadays, I can handle them okay, more or less.","TWN":"但現在對付起來應該沒有那麼難了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배나 소대장처럼 쉽게 처치하기엔 아직 멀었지만.","JPN":"先輩や小隊長のように簡単に倒すのはまだ難しいけど。","ENG":"Although I still have ways to go till I can defeat them as easily as my colleagues.","TWN":"雖然我距離前輩和小隊長那樣輕鬆取勝還差很多。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무...... 무슨 헛소리를 하는 거야?!","JPN":"そ……そんなバカげたことを信じるわけないでしょ？","ENG":"What... What are you blabbering about?","TWN":"你……你胡說什麼呢？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너 같은 애송이가 3종 침식체를 사냥했다니 그런 거짓말을 믿을 것 같아?","JPN":"あんたみたいな小娘が第3種侵食体を倒したなんて嘘、誰も信じないわ！","ENG":"A rookie nobody like you hunted a Category 3? You think anyone would fall for a ridiculous lie like that?","TWN":"你這樣的菜鳥怎麼可能狩獵3類侵蝕體，你以為我會相信這樣的謊話嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마음대로 생각해. 상관없으니까.","JPN":"信じるかどうかはご自由に。こっちは関係ないし。","ENG":"Think whatever you’d like. I really don't care.","TWN":"隨便你怎麼想吧。我無所謂。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도 미나 말은 믿기 힘들지만......!","JPN":"わ、私もミナちゃんの言うことは信じがたいけれど……！","ENG":"A-although I also have trouble believing exactly what she just said...","TWN":"我、我雖然也不敢相信……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"조금 전에 미나가 네 시뮬레이터 전투 기록을 갈아치운 건 사실이야!","JPN":"さっきミナちゃんがあなたのシミュレーター戦闘記録を更新したのは事実だよ！","ENG":"Mina did break your simulation record just now!","TWN":"但剛剛米娜確實打破了你的模擬器戰鬥記錄！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐? 비, 비켜 봐!","JPN":"は？　ちょっとどいて！","ENG":"What? M-move aside!","TWN":"什麼？讓、讓開！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>랭킹 순위를 출력합니다.</color>","JPN":"<color=#ffd34c>ランキング記録を出力します。</color>","ENG":"<color=#ffd34c>Displaying current rankings.</color>","TWN":"<color=#ffd34c>正在輸出統計排名。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>1등 – 옌 싱 란체스터</color>","JPN":"<color=#ffd34c>1位 – イェン・シング・ランチェスター</color>","ENG":"<color=#ffd34c>1st Place - Yen Xing Lanchester</color>","TWN":"<color=#ffd34c>第1名——嫣杏‧蘭賈斯特</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>2등 – 유미나, 레이. S</color>","JPN":"<color=#ffd34c>2位 – ヤナギ・ミナ、レイ.S</color>","ENG":"<color=#ffd34c>2nd Place - Yoo Mina, Ray S.</color>","TWN":"<color=#ffd34c>第2名——劉米娜＆雷伊.S</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>3등 – 나이엘 블루스틸</color>","JPN":"<color=#ffd34c>3位 – ナイエル・ブルースチール</color>","ENG":"<color=#ffd34c>3rd Place - Naielle Bluesteel</color>","TWN":"<color=#ffd34c>第3名——奈爾‧布魯斯提爾</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"......거짓말이야.","JPN":"……嘘だ。","ENG":"Lies...","TWN":"……這不是真的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이건 다 거짓말이라고! 내가 이 따위 헛소리를 믿을 것 같아?!","JPN":"こんなの嘘に決まってる！　私がこんなでたらめに騙されると思う！？","ENG":"These are all lies! Do you think I'd buy this load of bull?","TWN":"這一定是你們在騙我！以為我會相信這樣的謊話嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"보나마나 너희들이 시뮬레이터를 해킹했거나 뭔가 장난질을 쳤겠지!","JPN":"どうせあんたたちがシミュレーターにハッキングとか、何か手を加えたんでしょ！","ENG":"I'm sure you guys hacked into the simulator or played some other dirty trick!","TWN":"肯定是你們修改了模擬器資料或者耍了其他手段！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"정 네 말을 증명하고 싶으면 여기서 직접 보여 봐.","JPN":"言ってることが本当ならここで証明してみせて。","ENG":"If you really want to prove yourself, why don't you show me?","TWN":"如果是真的，就證明給我看。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그래, 차라리 잘됐네. 이 시뮬레이터는 최대 제 3종 침식체까지 구현할 수 있거든.","JPN":"そうよ、それがいいわ。このシミュレーターは最大で第3種侵食体まで再現できるからね。","ENG":"Actually, that'd be perfect. This thing can simulate up to a Category 3.","TWN":"嗯，這樣正好，這台模擬器最多可呈現3類侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 3종 침식체와 싸워 본 적이 있다면 겁낼 이유는 없겠지?","JPN":"あんたが第3種侵食体と戦ったことがあるなら怖がる必要はないでしょう？","ENG":"I'm sure you have nothing to fear if you've really fought a Category 3, right?","TWN":"如果你與3類侵蝕體戰鬥過的話，沒有理由害怕吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"안 돼! 3종 침식체 구현은 아직 테스트 중인 기능이라고!","JPN":"ダメだよ！　第3種侵食体の再現はまだテスト中の機能でしょ！","ENG":"No! The Category 3 feature is still under testing!","TWN":"不行！3類侵蝕體的呈現還是測試中的功能！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너무 심한 충격을 받으면 탑승자한테 후유증이 생길 수도 있어!","JPN":"シミュレーション中に大きなダメージを負うと、搭乗者に後遺症が残るかもしれないよ！","ENG":"If anything goes wrong, it could traumatize the user!","TWN":"如果衝擊過大，使用模擬器的人可能會留下後遺症！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"왜? 웃기지도 않은 거짓말이 들킬까 봐 겁나?","JPN":"へえー、適当に言った嘘がバレるのは怖くなってきたの？","ENG":"What's wrong? Are you scared your ridiculous lies will be exposed?","TWN":"怎麼？害怕了？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그럴 줄 알았지! 이 창피한 줄도 모르는 낙오자들!","JPN":"だろうね！　この恥知らずの落ちこぼれ！","ENG":"I knew it! You losers are so shameless!","TWN":"我就知道！你們這些不知羞恥的失敗者！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 해보지, 뭐.","JPN":"いいよ。やってみる。","ENG":"Fine. I'll give it a try.","TWN":"好吧，那就試試好了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미, 미나야! 자칫하면 정말 위험해질 수도 있어!","JPN":"ミ、ミナちゃん！　下手したら本当に危ない目にあっちゃうよ！","ENG":"M-Mina! This could get really dangerous!","TWN":"米、米娜！搞不好真的很危險！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"大丈夫。","ENG":"Don't worry.","TWN":"沒關係。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배와 넌 여기 와서 날 처음으로 도와 준 친구들이야.","JPN":"レイ先輩とミカは、ここで初めて私を助けてくれた友達なのに。","ENG":"You and Ray were the first people to help me here.","TWN":"雷伊前輩和你是在這裡第一次幫助我的朋友。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 사람들이 저딴 소리를 듣는 건, 마음에 안 드네.","JPN":"ここまで言いたい放題言われて、気に入らない。","ENG":"I don't like that you're treated like that.","TWN":"我不喜歡她這樣說你們。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나야......","JPN":"ミナちゃん……","ENG":"Mina...","TWN":"米娜……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맡겨 둬. 난 네가 말한 엘리트 카운터 같은 건 아니지만, 지옥의 수라장이란 건......","JPN":"任せて。私はあなたが言うようなエリートカウンターではないけど、地獄の修羅場は……","ENG":"You can count on me. I'm not the cream of the crop like you said, but as for hell...","TWN":"相信我。我雖然不是你口中的精英制裁者，但修羅地獄我還是見識過的……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음......","JPN":"えーと……","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까, 몇 번쯤 해쳐 나온 적이 있는 것 같거든.","JPN":"たぶん何回かは潜り抜けたことあると思う。","ENG":"I think I've been there and back several times, after all.","TWN":"所以，殺進殺出個幾次應該沒問題。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};